from flask import Flask, request, jsonify
from prometheus_client import Counter, Gauge, Histogram, generate_latest, CONTENT_TYPE_LATEST
import time

app = Flask(__name__)

# Create Prometheus metrics
REQUEST_COUNT = Counter('flask_request_count', 'Total request count', ['method', 'endpoint', 'status'])
REQUEST_LATENCY = Histogram('flask_request_latency_seconds', 'Request latency in seconds', ['method', 'endpoint'])
ACTIVE_REQUESTS = Gauge('flask_active_requests', 'Number of active requests')
BUSINESS_METRIC = Counter('business_metric_count', 'Business metric counter', ['action'])

@app.before_request
def start_timer():
    request.start_time = time.time()

@app.after_request
def record_metrics(response):
    duration = time.time() - request.start_time
    REQUEST_LATENCY.labels(method=request.method, endpoint=request.endpoint or 'unknown').observe(duration)
    REQUEST_COUNT.labels(method=request.method, endpoint=request.endpoint or 'unknown', status=response.status_code).inc()
    return response

@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': CONTENT_TYPE_LATEST}

@app.route('/health')
def health():
    return jsonify({'status': 'healthy'}), 200

@app.route('/business-action', methods=['POST'])
def business_action():
    BUSINESS_METRIC.labels(action='process').inc()
    return jsonify({'message': 'Business action processed'}), 200

@app.route('/slow-endpoint')
def slow_endpoint():
    time.sleep(0.1)
    return jsonify({'message': 'Slow endpoint response'}), 200

@app.route('/error-endpoint')
def error_endpoint():
    return jsonify({'error': 'Something went wrong'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)